package ru.memearena.tournament.application; import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty; import org.springframework.context.annotation.Profile; import org.springframework.scheduling.annotation.Scheduled; import org.springframework.stereotype.Component; import ru.memearena.tournament.infrastructure.TournamentMatchRepository; import java.time.*; @Profile("prod") @Component @ConditionalOnProperty(prefix="app.tournament",name="enabled",havingValue="true") public class TournamentScheduler{ private final TournamentCreationService creation; private final TournamentProgressionService progression; private final TournamentMatchRepository matches; private final Clock clock; public TournamentScheduler(TournamentCreationService c,TournamentProgressionService p,TournamentMatchRepository m,Clock clock){creation=c;progression=p;matches=m;this.clock=clock;} @Scheduled(cron="0 0 0 * * *",zone="${app.tournament.time-zone:Europe/Moscow}") public void createDaily(){creation.createToday();} @Scheduled(fixedDelayString="PT5M") public void progressDueRounds(){matches.findByStatusAndEndsAtLessThanEqual(ru.memearena.tournament.domain.TournamentMatchStatus.ACTIVE,Instant.now(clock)).stream().map(x->x.tournamentId).distinct().forEach(progression::advance);} }
